PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE _cf_METADATA (
        key INTEGER PRIMARY KEY,
        value BLOB
      );
CREATE TABLE hospitals (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  code TEXT UNIQUE NOT NULL,
  address TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE users (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER,
  username TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  role TEXT NOT NULL DEFAULT 'hospital', 
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, nutritionist_name TEXT, password_plain TEXT DEFAULT NULL, sub_role TEXT DEFAULT NULL, executive_title TEXT DEFAULT '',
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE vendors (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  name TEXT NOT NULL,
  category TEXT NOT NULL DEFAULT 'general', 
  tax_type TEXT NOT NULL DEFAULT 'mixed', 
  monthly_budget INTEGER DEFAULT 0,
  sort_order INTEGER DEFAULT 0,
  is_active INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, is_card_type INTEGER DEFAULT 0, card_subtype TEXT DEFAULT NULL, order_cycle TEXT DEFAULT 'daily',
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE monthly_settings (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  total_budget INTEGER DEFAULT 0,         
  event_budget INTEGER DEFAULT 0,         
  meal_price INTEGER DEFAULT 0,           
  food_waste_budget INTEGER DEFAULT 0,    
  working_days INTEGER DEFAULT 0,         
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, supply_budget INTEGER DEFAULT 0, card_budget INTEGER DEFAULT 0, waste_unit_price INTEGER DEFAULT 0,
  UNIQUE(hospital_id, year, month),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE daily_orders (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  vendor_id INTEGER NOT NULL,
  order_date TEXT NOT NULL,               
  taxable_amount INTEGER DEFAULT 0,       
  exempt_amount INTEGER DEFAULT 0,        
  vat_amount INTEGER DEFAULT 0,           
  total_amount INTEGER DEFAULT 0,         
  note TEXT,                              
  is_multi_day INTEGER DEFAULT 0,         
  multi_day_start TEXT,                   
  multi_day_end TEXT,                     
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, patient_category_id INTEGER DEFAULT NULL, order_date_actual TEXT, received_date TEXT, is_inspected INTEGER DEFAULT 0, inspection_memo TEXT, actual_amount INTEGER DEFAULT 0, inspected_at TEXT, inspected_by TEXT, inspection_status TEXT DEFAULT 'pending', deduction_amount INTEGER DEFAULT 0, input_source TEXT DEFAULT 'direct',
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (vendor_id) REFERENCES vendors(id)
);
CREATE TABLE daily_meals (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  meal_date TEXT NOT NULL,                
  
  breakfast_patient INTEGER DEFAULT 0,    
  breakfast_staff INTEGER DEFAULT 0,      
  breakfast_noncovered INTEGER DEFAULT 0, 
  breakfast_guardian INTEGER DEFAULT 0,   
  
  lunch_patient INTEGER DEFAULT 0,
  lunch_staff INTEGER DEFAULT 0,
  lunch_noncovered INTEGER DEFAULT 0,
  lunch_guardian INTEGER DEFAULT 0,
  
  dinner_patient INTEGER DEFAULT 0,
  dinner_staff INTEGER DEFAULT 0,
  dinner_noncovered INTEGER DEFAULT 0,
  dinner_guardian INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, custom_data TEXT DEFAULT '{}',
  UNIQUE(hospital_id, meal_date),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE employees (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  name TEXT NOT NULL,
  position TEXT NOT NULL,                 
  section TEXT NOT NULL DEFAULT 'cook',   
  phone TEXT,
  annual_leave_total INTEGER DEFAULT 15,  
  sort_order INTEGER DEFAULT 0,
  is_active INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, emp_number TEXT DEFAULT '', birth_date TEXT DEFAULT '', hire_date TEXT DEFAULT '', resign_date TEXT DEFAULT '', employment_type TEXT DEFAULT 'full', work_parts TEXT DEFAULT '[]', team TEXT DEFAULT 'cook', position_id INTEGER DEFAULT NULL, email TEXT DEFAULT '', address TEXT DEFAULT '', emergency_contact TEXT DEFAULT '', note TEXT DEFAULT '', health_cert_expire TEXT DEFAULT '', health_exam_date TEXT DEFAULT '', health_exam_status TEXT DEFAULT 'pending', updated_at TEXT DEFAULT '', salary_type TEXT NOT NULL DEFAULT 'monthly', base_salary REAL DEFAULT 0, ot_enabled INTEGER NOT NULL DEFAULT 0, night_allowance_enabled INTEGER NOT NULL DEFAULT 0, holiday_allowance_enabled INTEGER NOT NULL DEFAULT 0, holiday_policy_override TEXT DEFAULT NULL, work_type TEXT DEFAULT NULL, schedule_type TEXT DEFAULT 'flexible', work_cycle_start_date TEXT DEFAULT NULL, cycle_work_days INTEGER DEFAULT NULL, cycle_rest_days INTEGER DEFAULT NULL,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE daily_schedules (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  employee_id INTEGER NOT NULL,
  work_date TEXT NOT NULL,                
  shift_code TEXT NOT NULL DEFAULT 'a',   
  note TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, shift_id INTEGER DEFAULT NULL, leave_type TEXT DEFAULT NULL, is_overtime INTEGER DEFAULT 0, overtime_hours REAL DEFAULT 0, is_temp_staff INTEGER DEFAULT 0, is_night_work INTEGER DEFAULT 0, temp_type TEXT DEFAULT NULL, temp_hours REAL DEFAULT 0, basic_work_hours   REAL DEFAULT 0, night_work_hours   REAL DEFAULT 0, holiday_work_hours REAL DEFAULT 0, weekly_holiday_pay INTEGER DEFAULT 0,
  UNIQUE(hospital_id, employee_id, work_date),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id)
);
CREATE TABLE hospital_info (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER UNIQUE NOT NULL,
  
  hospital_type TEXT DEFAULT 'general',  
  address TEXT,
  
  licensed_beds INTEGER DEFAULT 0,       
  avg_inpatients INTEGER DEFAULT 0,      
  staff_count INTEGER DEFAULT 0,         
  guardian_ratio REAL DEFAULT 0,         
  
  operation_type TEXT DEFAULT 'direct',  
  consignment_company TEXT,              
  meals_per_day INTEGER DEFAULT 3,       
  current_meal_price INTEGER DEFAULT 0,  
  target_meal_price INTEGER DEFAULT 0,   
  supply_method TEXT DEFAULT 'mixed',    
  
  annual_budget INTEGER DEFAULT 0,       
  
  dietitian_name TEXT,                   
  dietitian_phone TEXT,                  
  admin_memo TEXT,                       
  
  current_year INTEGER,                  
  current_month INTEGER,                 
  closing_status TEXT DEFAULT 'open',    
  closing_requested_at DATETIME,         
  closing_approved_at DATETIME,          
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, main_specialty TEXT DEFAULT '', main_category TEXT DEFAULT 'other', main_category_custom TEXT, monthly_avg_budget INTEGER DEFAULT 0, care_type TEXT DEFAULT 'general', supply_exclude_keys TEXT DEFAULT NULL,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE category_budgets (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  category TEXT NOT NULL,               
  monthly_budget INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, year, month, category),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE monthly_closings (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  status TEXT DEFAULT 'open',           
  requested_at DATETIME,
  requested_by INTEGER,                 
  approved_at DATETIME,
  approved_by INTEGER,                  
  memo TEXT,
  UNIQUE(hospital_id, year, month),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE holidays (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  holiday_date TEXT NOT NULL UNIQUE,    
  name TEXT NOT NULL,                   
  is_auto INTEGER DEFAULT 1,            
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE notifications (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  to_user_id INTEGER,                   
  from_hospital_id INTEGER,
  type TEXT NOT NULL,                   
  title TEXT NOT NULL,
  message TEXT,
  is_read INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (from_hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE hospital_sessions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  user_id INTEGER NOT NULL,
  username TEXT NOT NULL,
  last_active_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  last_page TEXT DEFAULT 'dashboard',   
  is_active INTEGER DEFAULT 1,          
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, last_action TEXT DEFAULT NULL, role TEXT DEFAULT 'hospital',
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE food_waste_records (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  week INTEGER NOT NULL DEFAULT 1,      
  waste_amount REAL DEFAULT 0,          
  waste_cost INTEGER DEFAULT 0,         
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, year, month, week),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE daily_issues (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  issue_date TEXT NOT NULL,         
  issue_type TEXT NOT NULL,         
  issue_level TEXT NOT NULL DEFAULT 'warning',  
  message TEXT NOT NULL,
  extra_data TEXT,                  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE close_month_requests (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending',  
  requested_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  processed_at DATETIME,
  note TEXT,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE meal_custom_fields (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  field_key TEXT NOT NULL,        
  field_name TEXT NOT NULL,       
  sort_order INTEGER DEFAULT 0,   
  is_active INTEGER DEFAULT 1,    
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, unit_type TEXT DEFAULT 'meal',
  UNIQUE(hospital_id, field_key),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE hospital_patient_categories (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  category_key TEXT NOT NULL,        
  category_name TEXT NOT NULL,       
  order_code TEXT DEFAULT '',        
  sort_order INTEGER DEFAULT 0,
  is_active INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, budget_include_keys TEXT DEFAULT NULL, meals_include_keys TEXT DEFAULT NULL, extra_include_keys TEXT DEFAULT NULL, budget_include_supply INTEGER DEFAULT 0, budget_include_card INTEGER DEFAULT 0,
  UNIQUE(hospital_id, category_key),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE category_order_settings (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  patient_category_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  monthly_budget INTEGER DEFAULT 0,     
  target_meal_price INTEGER DEFAULT 0,  
  working_days INTEGER DEFAULT 0,       
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, daily_meal_count INTEGER DEFAULT 0, ref_meal_price INTEGER DEFAULT 0,
  UNIQUE(hospital_id, patient_category_id, year, month),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (patient_category_id) REFERENCES hospital_patient_categories(id)
);
CREATE TABLE card_expenses (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  vendor_id INTEGER NOT NULL,           
  expense_date TEXT NOT NULL,           
  vendor_name TEXT NOT NULL,            
  item_name TEXT NOT NULL,              
  purpose TEXT NOT NULL,                
  amount INTEGER NOT NULL DEFAULT 0,    
  memo TEXT,                            
  receipt_url TEXT,                     
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, expense_type TEXT NOT NULL DEFAULT '법인카드',
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (vendor_id) REFERENCES vendors(id)
);
CREATE TABLE order_inspections (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  order_id INTEGER NOT NULL,         
  hospital_id INTEGER NOT NULL,
  inspected_at TEXT NOT NULL,        
  inspected_by TEXT,                 
  original_amount INTEGER DEFAULT 0, 
  actual_amount INTEGER DEFAULT 0,   
  difference INTEGER DEFAULT 0,      
  memo TEXT,                         
  status TEXT DEFAULT 'completed',   
  created_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (order_id) REFERENCES daily_orders(id) ON DELETE CASCADE,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE ingredient_prices (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  ingredient_name TEXT NOT NULL,    
  unit TEXT DEFAULT 'kg',           
  unit_price INTEGER DEFAULT 0,     
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, source TEXT DEFAULT 'manual', total_amount INTEGER DEFAULT 0, total_quantity REAL DEFAULT 0, vendor_name TEXT DEFAULT '',
  UNIQUE(hospital_id, year, month, ingredient_name),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE inspection_issues (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  order_id INTEGER NOT NULL,         
  hospital_id INTEGER NOT NULL,
  vendor_name TEXT,                  
  item_name TEXT,                    
  issue_type TEXT NOT NULL,          
  issue_detail TEXT,                 
  deduction_amount INTEGER DEFAULT 0,
  order_amount INTEGER DEFAULT 0,    
  actual_amount INTEGER DEFAULT 0,   
  created_at TEXT DEFAULT (datetime('now')),
  created_by TEXT,
  FOREIGN KEY (order_id) REFERENCES daily_orders(id) ON DELETE CASCADE,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE care_type_codes (
  code        TEXT PRIMARY KEY,           
  label_ko    TEXT NOT NULL,              
  sort_order  INTEGER DEFAULT 99,
  is_active   INTEGER DEFAULT 1,
  created_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE transaction_item_categories (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL UNIQUE,          
  code TEXT NOT NULL UNIQUE,          
  color TEXT DEFAULT '#6b7280',       
  sort_order INTEGER DEFAULT 0,
  is_active INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE transaction_files (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  file_name TEXT NOT NULL,            
  file_type TEXT NOT NULL,            
  file_size INTEGER DEFAULT 0,        
  file_data TEXT,                     
  vendor_name TEXT,                   
  document_year INTEGER,              
  document_month INTEGER,             
  parse_status TEXT DEFAULT 'pending', 
  parse_error TEXT,                   
  row_count INTEGER DEFAULT 0,        
  uploaded_by TEXT DEFAULT 'admin',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, date_from TEXT DEFAULT NULL, date_to   TEXT DEFAULT NULL,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE transaction_documents (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  file_id INTEGER NOT NULL,
  hospital_id INTEGER NOT NULL,
  vendor_name TEXT NOT NULL,          
  document_date TEXT,                 
  document_number TEXT,               
  document_year INTEGER NOT NULL,
  document_month INTEGER NOT NULL,
  total_amount INTEGER DEFAULT 0,     
  taxable_amount INTEGER DEFAULT 0,   
  tax_amount INTEGER DEFAULT 0,       
  nontaxable_amount INTEGER DEFAULT 0,
  item_count INTEGER DEFAULT 0,       
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, trade_period TEXT DEFAULT '', date_from TEXT DEFAULT NULL, date_to   TEXT DEFAULT NULL,
  FOREIGN KEY (file_id) REFERENCES transaction_files(id) ON DELETE CASCADE,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE transaction_items (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  document_id INTEGER NOT NULL,
  file_id INTEGER NOT NULL,
  hospital_id INTEGER NOT NULL,
  vendor_name TEXT NOT NULL,
  document_year INTEGER NOT NULL,
  document_month INTEGER NOT NULL,
  item_name TEXT NOT NULL,            
  item_name_normalized TEXT,          
  category_id INTEGER,                
  quantity REAL DEFAULT 0,            
  unit TEXT DEFAULT '',               
  unit_price INTEGER DEFAULT 0,       
  amount INTEGER DEFAULT 0,           
  tax_type TEXT DEFAULT 'taxable',    
  tax_amount INTEGER DEFAULT 0,       
  raw_row TEXT,                       
  is_verified INTEGER DEFAULT 0,      
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, item_code TEXT DEFAULT '', spec TEXT DEFAULT '', supplier_category TEXT DEFAULT '', date_from TEXT DEFAULT NULL, date_to   TEXT DEFAULT NULL,
  FOREIGN KEY (document_id) REFERENCES transaction_documents(id) ON DELETE CASCADE,
  FOREIGN KEY (file_id) REFERENCES transaction_files(id) ON DELETE CASCADE,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (category_id) REFERENCES transaction_item_categories(id)
);
CREATE TABLE transaction_ai_analysis (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  analysis_year INTEGER NOT NULL,
  analysis_month INTEGER NOT NULL,
  analysis_type TEXT NOT NULL,        
  total_amount INTEGER DEFAULT 0,
  taxable_ratio REAL DEFAULT 0,       
  top_vendor TEXT,                    
  top_vendor_ratio REAL DEFAULT 0,    
  top_items TEXT,                     
  category_breakdown TEXT,            
  monthly_comparison TEXT,            
  
  alert_price_rise TEXT,              
  alert_qty_surge TEXT,               
  alert_vendor_concentration TEXT,    
  alert_tax_change TEXT,              
  alert_missing_data TEXT,            
  
  cross_analysis_summary TEXT,        
  cross_discrepancies TEXT,           
  analysis_text TEXT,                 
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE transaction_order_cross (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  cross_year INTEGER NOT NULL,
  cross_month INTEGER NOT NULL,
  item_name TEXT NOT NULL,
  item_name_normalized TEXT,
  vendor_name TEXT,
  
  ordered_quantity REAL DEFAULT 0,
  ordered_unit_price INTEGER DEFAULT 0,
  ordered_amount INTEGER DEFAULT 0,
  
  invoice_quantity REAL DEFAULT 0,
  invoice_unit_price INTEGER DEFAULT 0,
  invoice_amount INTEGER DEFAULT 0,
  
  qty_diff REAL DEFAULT 0,            
  qty_diff_ratio REAL DEFAULT 0,      
  price_diff INTEGER DEFAULT 0,       
  price_diff_ratio REAL DEFAULT 0,    
  amount_diff INTEGER DEFAULT 0,      
  alert_level TEXT DEFAULT 'normal',  
  alert_memo TEXT,                    
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE diet_categories (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id   INTEGER NOT NULL,
  parent_type   TEXT NOT NULL CHECK(parent_type IN ('patient','therapy','noncovered','staff')),
  diet_key      TEXT NOT NULL,          
  diet_name     TEXT NOT NULL,          
  is_active     INTEGER DEFAULT 1,      
  show_in_input INTEGER DEFAULT 1,      
  sort_order    INTEGER DEFAULT 0,
  target_meal_price INTEGER DEFAULT 0,  
  monthly_budget    INTEGER DEFAULT 0,  
  legacy_field_key  TEXT DEFAULT NULL,  
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at    DATETIME DEFAULT CURRENT_TIMESTAMP, patient_group TEXT DEFAULT NULL, diet_level TEXT DEFAULT 'group', include_in_meal_price INTEGER DEFAULT 0, linked_patient_group TEXT DEFAULT NULL,
  UNIQUE(hospital_id, diet_key),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE diet_category_presets (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  parent_type TEXT NOT NULL,
  preset_key  TEXT NOT NULL UNIQUE,
  preset_name TEXT NOT NULL,
  sort_order  INTEGER DEFAULT 0
, linked_patient_group TEXT DEFAULT NULL);
CREATE TABLE hospital_meal_price_settings (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id   INTEGER NOT NULL,
  
  noncovered_include_ids TEXT DEFAULT '[]',
  
  base_include_keys      TEXT DEFAULT '["staff","guardian"]',
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE invoice_supplier_classifications (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  vendor_name TEXT NOT NULL,
  category_name TEXT NOT NULL,
  mapped_category_id INTEGER,
  sort_order INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, vendor_name, category_name),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE hospital_invoice_vendors (
  id                  INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id         INTEGER NOT NULL,
  vendor_name         TEXT NOT NULL,
  vendor_name_norm    TEXT NOT NULL DEFAULT '',
  description         TEXT DEFAULT '',
  skip_rows           INTEGER DEFAULT 4,
  col_code            INTEGER DEFAULT 0,
  col_name            INTEGER DEFAULT 1,
  col_spec            INTEGER DEFAULT 2,
  col_unit            INTEGER DEFAULT 3,
  col_qty             INTEGER DEFAULT 4,
  col_price           INTEGER DEFAULT 5,
  col_amount          INTEGER DEFAULT 6,
  col_vat             INTEGER DEFAULT 7,
  col_total           INTEGER DEFAULT 8,
  cat_mode            TEXT DEFAULT 'subtotal',
  col_category        INTEGER DEFAULT NULL,
  test_status         TEXT DEFAULT 'untested',
  test_sample_rows    TEXT DEFAULT NULL,
  test_verified_at    DATETIME DEFAULT NULL,
  last_upload_at      DATETIME DEFAULT NULL,
  last_upload_year    INTEGER DEFAULT NULL,
  last_upload_month   INTEGER DEFAULT NULL,
  upload_count        INTEGER DEFAULT 0,
  is_active           INTEGER DEFAULT 1,
  sort_order          INTEGER DEFAULT 0,
  created_at          DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at          DATETIME DEFAULT CURRENT_TIMESTAMP, vendor_id INTEGER REFERENCES vendors(id), upload_mode TEXT DEFAULT 'monthly', period_type TEXT DEFAULT 'auto',
  UNIQUE(hospital_id, vendor_name_norm),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE order_multiday_settings (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  order_date TEXT NOT NULL,          
  day_count INTEGER NOT NULL DEFAULT 1, 
  multi_day_end TEXT,                
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, order_date),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE employee_positions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER,                          
  team TEXT NOT NULL DEFAULT 'cook',            
  name TEXT NOT NULL,                           
  sort_order INTEGER NOT NULL DEFAULT 0,        
  is_default INTEGER NOT NULL DEFAULT 0,        
  is_active INTEGER NOT NULL DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE schedule_shifts (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  shift_code TEXT NOT NULL,              
  shift_name TEXT NOT NULL,              
  start_time TEXT NOT NULL DEFAULT '09:00',  
  end_time TEXT NOT NULL DEFAULT '18:00',    
  color TEXT NOT NULL DEFAULT '#3B82F6',     
  team TEXT DEFAULT NULL,                
  is_active INTEGER NOT NULL DEFAULT 1,
  sort_order INTEGER NOT NULL DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, shift_code),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE employee_leaves (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  employee_id INTEGER NOT NULL,
  year INTEGER NOT NULL,                 
  leave_type TEXT NOT NULL DEFAULT 'annual',  
  total_days REAL NOT NULL DEFAULT 0,    
  used_days REAL NOT NULL DEFAULT 0,     
  note TEXT DEFAULT '',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, carried_over_days REAL NOT NULL DEFAULT 0, allowance_paid INTEGER NOT NULL DEFAULT 0, allowance_paid_at TEXT, initial_used_days REAL NOT NULL DEFAULT 0, is_initial_setup INTEGER NOT NULL DEFAULT 0,
  UNIQUE(hospital_id, employee_id, year, leave_type),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id)
);
CREATE TABLE schedule_min_staff (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  position_id INTEGER,                   
  team TEXT DEFAULT NULL,                
  min_count INTEGER NOT NULL DEFAULT 1,  
  note TEXT DEFAULT '',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, position_id, team),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE substitute_off_days (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER DEFAULT NULL,       
  off_date    TEXT    NOT NULL,           
  off_name    TEXT    NOT NULL DEFAULT '대체휴무',  
  off_reason  TEXT    DEFAULT '',         
  created_by  TEXT    DEFAULT '',         
  created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, off_date)
);
CREATE TABLE labor_cost_settings (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id   INTEGER NOT NULL,
  cost_type     TEXT    NOT NULL,
  unit_price    REAL    NOT NULL DEFAULT 0,
  description   TEXT    DEFAULT '',
  updated_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, cost_type),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE employee_ot_settings (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id     INTEGER NOT NULL,
  employee_id     INTEGER NOT NULL,
  hourly_wage     REAL    DEFAULT 0,
  ot_rate         REAL    DEFAULT 1.5,
  night_rate      REAL    DEFAULT 0.5,
  note            TEXT    DEFAULT '',
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, employee_id),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id)
);
CREATE TABLE hospital_work_settings (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  setting_key TEXT NOT NULL,        
  setting_value TEXT NOT NULL,      
  description TEXT DEFAULT '',
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, setting_key),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE employee_leave_history (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  employee_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL,
  leave_date TEXT NOT NULL,         
  leave_subtype TEXT NOT NULL,      
  note TEXT DEFAULT '',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id)
);
CREATE TABLE dispatch_schedules (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id  INTEGER NOT NULL,
  work_date    TEXT    NOT NULL,   
  disp_type    TEXT    NOT NULL,   
  count        INTEGER DEFAULT 1, 
  hours        REAL    DEFAULT 0, 
  unit_price   REAL    DEFAULT 0, 
  memo         TEXT    DEFAULT '',
  created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE monthly_work_summary (
  id                   INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id          INTEGER NOT NULL,
  employee_id          INTEGER NOT NULL,
  year                 INTEGER NOT NULL,
  month                INTEGER NOT NULL,
  work_days            INTEGER DEFAULT 0,   
  basic_hours          REAL    DEFAULT 0,   
  ot_hours             REAL    DEFAULT 0,   
  night_hours          REAL    DEFAULT 0,   
  holiday_hours        REAL    DEFAULT 0,   
  weekly_holiday_days  INTEGER DEFAULT 0,   
  annual_leave_used    REAL    DEFAULT 0,   
  ot_cost              REAL    DEFAULT 0,   
  night_cost           REAL    DEFAULT 0,   
  holiday_cost         REAL    DEFAULT 0,   
  weekly_holiday_cost  REAL    DEFAULT 0,   
  updated_at           DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, employee_id, year, month),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id)
);
CREATE TABLE external_workers (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id  INTEGER NOT NULL,
  name         TEXT    NOT NULL,           
  worker_type  TEXT    NOT NULL DEFAULT 'dispatch',  
  memo         TEXT    DEFAULT '',
  is_active    INTEGER DEFAULT 1,          
  created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE external_schedules (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id     INTEGER NOT NULL,
  worker_id       INTEGER NOT NULL,        
  work_date       TEXT    NOT NULL,        
  shift_type      TEXT    NOT NULL,        
  unit_price      REAL    DEFAULT 0,       
  note            TEXT    DEFAULT '',
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(hospital_id, worker_id, work_date),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (worker_id)   REFERENCES external_workers(id)
);
CREATE TABLE schedule_share_tokens (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  employee_id INTEGER NOT NULL,
  token TEXT NOT NULL UNIQUE,           
  created_at TEXT DEFAULT (datetime('now')),
  expires_at TEXT DEFAULT NULL,         
  is_active INTEGER DEFAULT 1,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id)
);
CREATE TABLE team_share_tokens (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL UNIQUE,  
  token TEXT NOT NULL UNIQUE,
  created_at TEXT DEFAULT (datetime('now')),
  is_active INTEGER DEFAULT 1,
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE schedule_change_log (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id INTEGER NOT NULL,
  employee_id INTEGER NOT NULL,
  work_date TEXT NOT NULL,          
  old_shift_code TEXT,              
  new_shift_code TEXT,              
  changed_by INTEGER,               
  changed_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id)
);
CREATE TABLE work_settings_history (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id  INTEGER NOT NULL,
  setting_key  TEXT    NOT NULL,
  prev_value   TEXT,
  new_value    TEXT,
  changed_by   TEXT    NOT NULL,
  changed_at   DATETIME DEFAULT (datetime('now','localtime')),
  change_type  TEXT    NOT NULL DEFAULT 'manual',
  
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id)
);
CREATE TABLE off_grant_history (
  id                  INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id         INTEGER NOT NULL,
  employee_id         INTEGER,             
  target_date         TEXT    NOT NULL,    
  prev_off_type       TEXT,               
  new_off_type        TEXT,               
  base_off_type       TEXT,               
  prev_is_manual      INTEGER DEFAULT 0,  
  new_is_manual       INTEGER DEFAULT 0,  
  prev_lock_flag      INTEGER DEFAULT 0,
  new_lock_flag       INTEGER DEFAULT 0,
  changed_by          TEXT    NOT NULL,
  changed_at          DATETIME DEFAULT (datetime('now','localtime')),
  note                TEXT, change_type TEXT DEFAULT 'manual',               
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id)
);
CREATE TABLE employee_holiday_exceptions (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  hospital_id     INTEGER NOT NULL,
  employee_id     INTEGER NOT NULL,
  holiday_date    TEXT    NOT NULL,   
  holiday_name    TEXT,               
  
  applied_policy  TEXT    NOT NULL DEFAULT 'off',
  
  
  
  
  allowance_paid  INTEGER DEFAULT 0,   
  substitute_date TEXT    DEFAULT NULL, 
  
  policy_source   TEXT    DEFAULT 'hospital',
  
  
  note            TEXT,
  created_by      TEXT    NOT NULL DEFAULT 'system',
  created_at      DATETIME DEFAULT (datetime('now','localtime')),
  updated_at      DATETIME DEFAULT (datetime('now','localtime')),
  FOREIGN KEY (hospital_id) REFERENCES hospitals(id),
  FOREIGN KEY (employee_id) REFERENCES employees(id),
  UNIQUE(hospital_id, employee_id, holiday_date)
);
CREATE TABLE monthly_leave_grants (
  id                INTEGER  PRIMARY KEY AUTOINCREMENT,
  hospital_id       INTEGER  NOT NULL,
  employee_id       INTEGER  NOT NULL,

  
  grant_year        INTEGER  NOT NULL,   
  grant_month       INTEGER  NOT NULL,  

  
  target_year       INTEGER  NOT NULL,  
  target_month      INTEGER  NOT NULL, 

  days_granted      REAL     NOT NULL DEFAULT 1,   
  grant_type        TEXT     NOT NULL DEFAULT 'auto',  
  status            TEXT     NOT NULL DEFAULT 'active', 

  
  attendance_days   INTEGER  DEFAULT NULL,  
  working_days      INTEGER  DEFAULT NULL,  
  absence_days      INTEGER  DEFAULT NULL,  

  note              TEXT     DEFAULT '',
  created_at        DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at        DATETIME DEFAULT CURRENT_TIMESTAMP,

  UNIQUE(hospital_id, employee_id, target_year, target_month),
  FOREIGN KEY (hospital_id)  REFERENCES hospitals(id),
  FOREIGN KEY (employee_id)  REFERENCES employees(id)
);
CREATE TABLE monthly_leave_audit (
  id            INTEGER  PRIMARY KEY AUTOINCREMENT,
  hospital_id   INTEGER  NOT NULL,
  employee_id   INTEGER  NOT NULL,
  grant_id      INTEGER  DEFAULT NULL,  

  action        TEXT     NOT NULL,
  
  
  
  
  
  

  before_value  TEXT     DEFAULT NULL,  
  after_value   TEXT     DEFAULT NULL,  
  actor_id      INTEGER  DEFAULT NULL,  
  actor_role    TEXT     DEFAULT NULL,  
  reason        TEXT     DEFAULT '',    

  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,

  FOREIGN KEY (hospital_id)  REFERENCES hospitals(id),
  FOREIGN KEY (employee_id)  REFERENCES employees(id)
);
